#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;LSET&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;summary&lt;/span&gt;: &lt;span class=&#34;title&#34;&gt;Set&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;the&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;value&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;of&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;an&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;element&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;in&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;a&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;list&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;by&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;its&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;index&lt;/span&gt;（通过索引设置列表中元素的值）&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;since&lt;/span&gt;: 1.0.0&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;title&#34;&gt;LTRIM&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;key&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;start&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;stop&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#3